from typing import List, Optional

def buildTree(preorder: List[int], inorder: List[int]) -> Optional[object]:
    index_map = {val: i for i, val in enumerate(inorder)}

    def helper(pre_start: int, pre_end: int, in_start: int, in_end: int) -> Optional[object]:
        if pre_start > pre_end or in_start > in_end:
            return None
        root_val = preorder[pre_start]
        root = type('TreeNode', (), {'val': root_val, 'left': None, 'right': None})()
        root_idx = index_map[root_val]
        left_size = root_idx - in_start
        root.left = helper(pre_start + 1, pre_start + left_size, in_start, root_idx - 1)
        root.right = helper(pre_start + left_size + 1, pre_end, root_idx + 1, in_end)
        return root

    return helper(0, len(preorder) - 1, 0, len(inorder) - 1)
